namespace sv_b104049cd7504a8b9e7f02c8ba2fc4f0.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts and notifies all subscribers.
/// Scoped lifetime ensures each circuit (user session) has independent state.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int LowStockCount { get; private set; }

    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += OnWarehouseChanged;
    }

    /// <summary>Simulates a database query returning low-stock items.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Starts polling if not already running.  Reference-counted so multiple
    /// components can call Start/Stop independently.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(_cts.Token);
        }
    }

    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            CancelTimer();
        }
    }

    /// <summary>Force an immediate refresh (e.g. after warehouse change).</summary>
    public async Task RefreshAsync()
    {
        LowStockCount = await GetLowStockCountAsync(_warehouseState.Current.Id);
        OnAlertCountChanged?.Invoke();
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire immediately on start, then every 10 seconds.
        await RefreshAsync();

        try
        {
            while (_timer is not null && await _timer.WaitForNextTickAsync(ct))
            {
                await RefreshAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on stop/dispose.
        }
    }

    private async void OnWarehouseChanged()
    {
        if (_subscriberCount > 0)
        {
            await RefreshAsync();
        }
    }

    private void CancelTimer()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= OnWarehouseChanged;
        CancelTimer();
    }
}

